}

func blindActive(w *World) bool {
        for _, e := range w.Effects {
                if e.ID == "blind" && w.Turn < e.ExpiryTurn {
                        return true
                }
        }
        return false
}

func snapToC2(effects []EffectState) []c2.EffectSnap {
        out := make([]c2.EffectSnap, len(effects))
